Javascript.logic:
var caseNumber = Services.getValue(this.dataBinding);
if(!CaseManUtils.isBlank(caseNumber) && CaseNumber.validate() == null) {
	getCaseDetails(caseNumber);
}
else {
	Services.setValue(_caseNumberExistsXPath, "false");
}

Javascript.validate:
var caseNumber = Services.getValue(this.dataBinding);
var errCode = null;
if(!CaseManUtils.isBlank(caseNumber)) {
	errCode = CaseManValidationHelper.validateCaseNumber(caseNumber);
}
return errCode;

Javascript.miscCode:
	Status_RunReportButton.validationList = ["CaseNumber"];
	
	var _caseNumberExistsXPath = "/ds/var/page/OracleReportForm/CaseNumberExists";
	
	Status_RunReportButton.enableOn = [_caseNumberExistsXPath];
	Status_RunReportButton.isEnabled = function()
	{
		if(Services.getValue(_caseNumberExistsXPath) == "true") {
			return true;
		}
        return false;
	}
	
	function getCaseDetails(caseNumber)
	{
		var params = new ServiceParams();
		params.addSimpleParameter("caseNumber", caseNumber);
		Services.callService("getCase", params, getCase, true);
	}
	
	function getCase()
	{
	}
	
	getCase.onSuccess = function(dom)
	{
		//debugger;
		if(dom != null) {
			var results = dom.selectSingleNode("/ds/ManageCase");
			if(results != null) {
				var caseOwningCourtNode = results.selectSingleNode("/ds/ManageCase/OwningCourtCode");
				var caseOwningCourt = XML.getNodeTextContent(caseOwningCourtNode);
				if (Services.getValue(PAGE_XPATH + "/tmp/OwningCourtCode") == caseOwningCourt)
				{
					Services.replaceNode("/ds/ManageCase", results);
					Services.setValue(_caseNumberExistsXPath, "true");
				}
				else
				{
					this.onError();
				}
			}
			else {
				this.onError();
			}
		}
		else {
			this.onError();
		}
	}
	getCase.onError = function()
	{
		Services.setValue(_caseNumberExistsXPath, "false");
		alert("Unknown Case Number. Please Enter Valid Case Number");
		Services.setValue(CaseNumber.dataBinding, "");
		Services.removeNode(DATA_XPATH + "/Parties");
	}
